#!/usr/bin/env python3
"""encode-ssm-models.py — HF → KNOT encoder for SSM/recurrent architectures.

Supports:
  - state-spaces/mamba-2.8b-hf        (Mamba-1, S6 selective scan)
  - mistralai/mamba-codestral-7B-v0.1  (Mamba-2 SSD, backbone.layers naming)
  - tiiuae/falcon-mamba-7b             (FalconMamba, Mamba-2 SSD)
  - RWKV/RWKV7-Goose-World3-2.9B-HF   (RWKV-7)
  - ai21labs/AI21-Jamba-1.5-Mini       (Jamba: interleaved Mamba-2 + Transformer)
  - tiiuae/Falcon-H1-7B-Reasoning      (Falcon-H1: interleaved Mamba-2 + Transformer)

Writes KNOT format files (magic "KNOT", JSON metadata, raw tensor bytes)
compatible with fat-station's KnotWeights::load_mmap loader.

Quantization: large projection matrices are Q8_0-quantized (32-element
blocks: 1 f32 absmax + 32 i8 values). Small SSM parameters (A_log, D,
biases, low-rank matrices, norms) are kept F32.

Usage:
    python3 encode-ssm-models.py \\
        --model tiiuae/falcon-mamba-7b \\
        --output rknots/falcon-mamba-7b.knot \\
        --hf-token $HF_TOKEN

    python3 encode-ssm-models.py \\
        --model RWKV/RWKV7-Goose-World3-2.9B-HF \\
        --output rknots/rwkv7-2.9b.knot

    python3 encode-ssm-models.py \\
        --model state-spaces/mamba-2.8b-hf \\
        --output rknots/mamba-2.8b.knot \\
        --max-layers 4   # fast iteration

Tier-1 transformer candidates (encode with encode-knot.py, not this script):
  HuggingFaceTB/SmolLM2-360M-Instruct  →  smollm2-360m       (llama, 360M)
  google/gemma-3-1b-it                  →  gemma3-1b-it        (gemma3, 1B)
  deepseek-ai/DeepSeek-R1-Distill-Qwen-1.5B → deepseek-r1-1.5b (qwen2, 1.5B)
  stabilityai/stablelm-zephyr-3b        →  stablelm-3b         (stablelm, 3B)
  google/gemma-3-4b-it                  →  gemma3-4b-it        (gemma3, 4B)
  google/gemma-4-e4b-it                 →  gemma4-e4b-it       (gemma3, 4B)
  Qwen/Qwen2.5-Coder-7B-Instruct        →  qwen-edit           (qwen2, 7B)
  Qwen/Qwen3-30B-A3B                    →  qwen3-30b-a3b       (qwen3/MoE, 30B)
"""
from __future__ import annotations

import argparse
import json
import os
import re
import struct
import sys
from pathlib import Path
from typing import Any

import numpy as np
import ml_dtypes  # registers bfloat16 with numpy so safetensors can decode bf16 tensors

# RWKV-7 uses trust_remote_code which imports fla. transformers.check_imports
# raises if fla is absent, even though RWKV-7's custom code handles it with
# try/except. Patch to allow the soft fallback to pure-PyTorch kernels.
def _bypass_fla_check():
    try:
        import transformers.dynamic_module_utils as _dmu
        _orig = _dmu.check_imports
        def _patched(filename, *a, **kw):
            try:
                return _orig(filename, *a, **kw)
            except ImportError as e:
                if "fla" in str(e):
                    return []
                raise
        _dmu.check_imports = _patched
    except Exception:
        pass

_bypass_fla_check()

# ─────────────────────────────────────────────────────────────────────────────
# Q8_0 quantization (compatible with llama.cpp / fat-station dequant kernel)
# Block size = 32 elements: 4-byte f32 absmax + 32 signed bytes.
# ─────────────────────────────────────────────────────────────────────────────

Q8_0_BLOCK = 32

def _to_f32(raw: "np.ndarray") -> "np.ndarray":
    if "bfloat16" in str(raw.dtype):
        u16 = np.frombuffer(raw.tobytes(), dtype=np.uint16)
        return (u16.astype(np.uint32) << 16).view(np.float32).reshape(raw.shape)
    return raw.astype(np.float32)

def _q8_0_encode(arr: np.ndarray) -> bytes:
    """Quantize to GGUF-standard Q8_0: per 32-elem block = fp16 scale d (2 bytes)
    + 32 int8. d = amax/127; qs[j] = round(x[j]/d); dequant x = d*qs. MUST match
    the runtime dequantize_q8_0_row (math.rs:153): 34-byte blocks, LE fp16 scale,
    then 32 i8. The old 4-byte-f32-absmax layout (36 bytes) mismatched stride +
    scale type -> every Q8_0 tensor dequantized to garbage / NaN."""
    arr = arr.astype(np.float32).flatten()
    pad = (-len(arr)) % Q8_0_BLOCK
    if pad:
        arr = np.pad(arr, (0, pad))
    # Vectorized (numpy) -- per-block Python loop is the bottleneck for 7B models.
    blocks = arr.reshape(-1, Q8_0_BLOCK)
    amax = np.abs(blocks).max(axis=1)
    d = amax / 127.0
    with np.errstate(divide="ignore", invalid="ignore"):
        inv = np.where(d > 0.0, 1.0 / d, 0.0)
    q = np.clip(np.round(blocks * inv[:, None]), -127, 127).astype(np.int8)
    d16 = d.astype(np.float16)
    out = np.empty((blocks.shape[0], 2 + Q8_0_BLOCK), dtype=np.uint8)
    out[:, :2] = d16.view(np.uint8).reshape(-1, 2)
    out[:, 2:] = q.view(np.uint8)
    return out.tobytes()


def _q8_0_n_bytes(n_elems: int) -> int:
    n_blocks = (n_elems + Q8_0_BLOCK - 1) // Q8_0_BLOCK
    return n_blocks * (2 + Q8_0_BLOCK)  # GGUF Q8_0: 2-byte fp16 scale + 32 i8


# ─────────────────────────────────────────────────────────────────────────────
# KNOT format writer
# ─────────────────────────────────────────────────────────────────────────────

class KnotWriter:
    """Streams tensors to a temp file; writes final KNOT on close.

    Streaming avoids accumulating the full model payload in RAM — critical for
    large MoE models (e.g. Jamba-1.5-Mini ~52B params) that OOM if held as a
    bytearray in-process.  Tensors are encoded and written one-by-one; only
    per-tensor metadata (name, type, offset, length) is kept in memory.
    """

    def __init__(self, name: str, arch: str, config: dict[str, Any]):
        import tempfile
        self._name = name
        self._arch = arch
        self._config = config
        self._meta: list[tuple[str, str, int, int]] = []  # (canon, qtype, offset, length)
        self._tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".knot.tmp")
        self._offset = 0

    def _stream(self, data: bytes, name: str, qtype: str) -> None:
        self._tmp.write(data)
        self._meta.append((name, qtype, self._offset, len(data)))
        self._offset += len(data)

    def add_f32(self, name: str, arr: np.ndarray) -> None:
        self._stream(arr.astype(np.float32).flatten().tobytes(), name, "F32")

    def add_q8(self, name: str, arr: np.ndarray) -> None:
        self._stream(_q8_0_encode(arr), name, "Q8_0")

    def add_auto(self, name: str, arr: np.ndarray, large_threshold: int = 65536) -> None:
        """Q8_0 for large matrices; F32 for small parameters."""
        if arr.size >= large_threshold:
            self.add_q8(name, arr)
        else:
            self.add_f32(name, arr)

    def write(self, path: Path) -> None:
        import os, shutil
        self._tmp.flush()

        tensor_meta: dict[str, Any] = {}
        for canon, qtype, offset, length in self._meta:
            key = canon.replace(".", "_") + ".bin"
            tensor_meta[key] = {"offset": offset, "length": length, "type": qtype}

        meta = {
            "name": self._name,
            "arch": self._arch,
            "config": self._config,
            "tensors": tensor_meta,
        }
        meta_bytes = json.dumps(meta).encode()

        magic = b"KNOT"
        version = struct.pack("<H", 1)
        meta_len = struct.pack("<I", len(meta_bytes))
        header = magic + version + meta_len + meta_bytes
        pad = (-len(header)) % 4
        header += b"\x00" * pad
        header += b"\x20"  # codec marker

        path.parent.mkdir(parents=True, exist_ok=True)
        with open(path, "wb") as f:
            f.write(header)
            self._tmp.seek(0)
            shutil.copyfileobj(self._tmp, f)

        tmp_path = self._tmp.name
        self._tmp.close()
        os.unlink(tmp_path)

        size_mb = path.stat().st_size / 1024 / 1024
        print(f"[knot] wrote {path} ({size_mb:.1f} MB, {len(self._meta)} tensors)",
              file=sys.stderr)


