# ─────────────────────────────────────────────────────────────────────────────
# Mamba-2 SSD (mistralai/mamba-codestral-7B-v0.1, model_type='mamba2')
# Same backbone.layers.N.mixer.* naming as Mamba-1 (in_proj is COMBINED [z,x,B,C,dt],
# dt_bias replaces dt_proj, no x_proj) PLUS a LEARNABLE gated RMSNorm inside the mixer
# (rms_norm=True → mixer.norm.weight is a real weight, unlike FalconMamba's weightless
# norm). Reuse the Mamba-1 patterns + append the ssm_norm rule.
# ─────────────────────────────────────────────────────────────────────────────
_MAMBA2_LAYER_PATTERNS: list[tuple[re.Pattern, str]] = _MAMBA1_LAYER_PATTERNS + [
    (re.compile(r"^backbone\.layers\.(\d+)\.mixer\.norm\.weight$"), "blk.{n}.ssm_norm.weight"),
]
_MAMBA2_GLOBALS = _MAMBA1_GLOBALS

# ─────────────────────────────────────────────────────────────────────────────
# FalconMamba (tiiuae/falcon-mamba-7b style) tensor name mapping
# Same backbone.layers.N.mixer.* naming as mamba-1 — reuse patterns directly.
#
# IMPORTANT — FalconMamba's B/C/dt RMSNorm is WEIGHTLESS. FalconMamba's defining
# feature over vanilla Mamba-1 is an RMSNorm applied to the SSM B, C, and dt
# (time_step) after the x_proj split (before dt_proj). But unlike Jamba — which
# ships LEARNABLE b_layernorm/c_layernorm/dt_layernorm weights — HF FalconMamba
# (`FalconMambaMixer`) calls a weightless `rms_forward(x, eps=mixer_rms_eps)`
# (verified verbatim in transformers `modeling_falcon_mamba.py`):
#     variance = x.pow(2).mean(-1, keepdim=True)
#     x = x * torch.rsqrt(variance + eps)        # NO learnable gamma
# The `b_c_rms`/`dt_rms` it registers are non-persistent all-ones buffers (Triton
# kernel placeholders), NOT checkpoint tensors. So there is NOTHING to capture
# here: the checkpoint has no b_norm/c_norm/dt_norm weights. The norm is applied
# at runtime (src/model_mamba.rs `mamba1_s6_step`, gated on arch=="falcon-mamba",
# eps = mixer_rms_eps default 1e-6). DO NOT add b_norm/c_norm/dt_norm patterns
# here — they would never match and the runtime needs no such tensors.
# ─────────────────────────────────────────────────────────────────────────────

_FALCON_MAMBA_LAYER_PATTERNS = _MAMBA1_LAYER_PATTERNS

_FALCON_MAMBA_GLOBALS = {
    "backbone.embeddings.weight": "token_embd.weight",
    "backbone.embedding.weight":  "token_embd.weight",
    "backbone.norm_f.weight":     "output_norm.weight",
    "lm_head.weight":             "output.weight",
    "backbone.lm_head.weight":    "output.weight",
}

